import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/auth/auth.service';
import { DataService } from './data.service';

@Component({
  selector: 'app-category',
  templateUrl: './category.component.html',
  styleUrls: ['./category.component.scss'],
  exportAs: 'category'
})
export class CategoryComponent implements OnInit {
  jobDefaults: any[] = [];
  pageSize = 10; // Hiển thị 10 mục mỗi trang
  page = 0;
  totalCount = 0;
  totalPage = 0;
  loading = false;

  constructor(
    private authService: AuthService,
    private router: Router,
    private dataService: DataService
  ) {}

  ngOnInit() {
    this.loadData(1); // Tải trang đầu tiên
  }

  loadData(page: number) {
    this.loading = true;
    this.dataService.getCategories(page, this.pageSize).subscribe({
      next: response => {
        if (response.status === 'FOUND') {
          this.jobDefaults = response.data.map((it: any) => ({
            ...it,
            icon: it?.icon || this.resolveIcon(it?.name),
          }));
          this.totalCount = response.totalCount;
          this.totalPage = response.totalPage;
          this.page = page - 1; // API dùng page bắt đầu từ 1
        }
        this.loading = false;
      },
      error: err => {
        console.error('Lỗi tải dữ liệu:', err);
        this.loading = false;
      }
    });
  }

  get displayed() {
    return this.jobDefaults; // Hiển thị toàn bộ dữ liệu của trang hiện tại
  }

  getPlaceholderCount(): number[] {
    const currentItems = this.displayed.length;
    const neededPlaceholders = this.pageSize - currentItems;
    return Array.from({ length: Math.max(0, neededPlaceholders) }, (_, i) => i);
  }

  next() {
    if (this.page >= this.totalPage - 1) {
      return; // Không chuyển nếu ở trang cuối
    }
    this.page++;
    this.loadData(this.page + 1);
  }

  prev() {
    if (this.page <= 0) {
      return; // Không chuyển nếu ở trang đầu
    }
    this.page--;
    this.loadData(this.page + 1);
  }

  gotoOtherPage(item: any) {
    if (this.authService.isCandidate() || (!this.authService.isCandidate() && !this.authService.isRecruiter())) {
      this.router.navigate(['/job'], { queryParams: { name: item.name, parentId: item.id } });
    } else {
      this.router.navigate(['/freelancer'], { queryParams: { name: item.name, parentId: item.id } });
    }
  }

  onImgError(ev: Event) {
    const target = ev.target as HTMLImageElement;
    target.src = '../assets/icons/briefcase.svg';
  }

  resolveIcon(name: string): string {
    const n = this.toSlug(name || '');
    if (n.includes('cong nghe') || n.includes('it') || n.includes('lap trinh')) {
      return '../assets/img/cong-nghe-thong-tin.png';
    }
    if (n.includes('ke toan') || n.includes('kiem toan') || n.includes('tai chinh')) {
      return '../assets/img/ke-toan-kiem-toan.png';
    }
    if (n.includes('y te') || n.includes('duoc')) {
      return '../assets/img/y-te-duoc.png';
    }
    if (n.includes('hanh chinh') || n.includes('van phong') || n.includes('tuyen sinh')) {
      return '../assets/img/hanh-chinh-van-phong.png';
    }
    if (n.includes('marketing') || n.includes('truyen thong') || n.includes('quang cao')) {
      return '../assets/img/marketing-truyen-thong-quang-cao.png';
    }
    if (n.includes('telesale')) {
      return '../assets/img/marketing-truyen-thong-quang-cao.png';
    }
    if (n.includes('bao chi') || n.includes('truyen hinh')) {
      return '../assets/img/dich-vu-khach-hang.png';
    }
    if (n.includes('giao duc') || n.includes('dao tao') || n.includes('truong hoc')) {
      return '../assets/img/giao-duc-dao-tao.png';
    }
    if (n.includes('nong lam') || n.includes('ngu nghiep')) {
      return '../assets/img/nong-lam-ngu-nghiep.png';
    }
    if (n.includes('san xuat') || n.includes('cong nhan')) {
      return '../assets/img/san-xuat.png';
    }
    if (n.includes('thiet ke') || n.includes('do hoa') || n.includes('designer')) {
      return '../assets/img/thiet-ke-do-hoa.png';
    }
    if (n.includes('khach san') || n.includes('nha hang') || n.includes('sale')) {
      return '../assets/img/khach-san-nha-hang.png';
    }
    if (n.includes('dien tu') || n.includes('vien thong')) {
      return '../assets/img/dien-tu-vien-thong.png';
    }
    if (n.includes('ban hang')) {
      return '../assets/img/kinh-doanh-ban-hang.png';
    }
    if (n.includes('kinh doanh')) {
      return '../assets/img/ban-le-ban-si.png';
    }
    if (n.includes('van hanh')) {
      return '../assets/img/logistics.png';
    }
    if (n.includes('dich vu') || n.includes('customer') || n.includes('cs')) {
      return '../assets/img/tu-van.png';
    }
    return '../assets/icons/briefcase.svg';
  }

  private toSlug(str: string): string {
    return str
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .toLowerCase();
  }
}
